# monitoring/error_budget.py
# Compute error budgets and burn rates for GenAI SLOs.
from dataclasses import dataclass
from typing import Optional

@dataclass
class ErrorBudget:
    slo_name: str
    slo_target: float       # e.g. 0.999 for 99.9%
    window_days: int        # e.g. 30
    current_value: float    # current measured SLI

    @property
    def budget_fraction(self) -> float:
        # Fraction of requests allowed to fail (or miss target)
        return 1.0 - self.slo_target

    @property
    def error_rate(self) -> float:
        # How much we are currently missing by
        return max(0.0, self.slo_target - self.current_value)

    @property
    def burn_rate(self) -> float:
        # How fast we are consuming the budget
        if self.budget_fraction == 0:
            return float('inf') if self.error_rate > 0 else 0.0
        return self.error_rate / self.budget_fraction

    @property
    def budget_consumed_fraction(self) -> float:
        if self.budget_fraction == 0:
            return 1.0 if self.error_rate > 0 else 0.0
        return min(1.0, self.error_rate / self.budget_fraction)

    @property
    def budget_remaining_fraction(self) -> float:
        return 1.0 - self.budget_consumed_fraction

    @property
    def days_until_exhausted(self) -> Optional[float]:
        if self.burn_rate == 0:
            return None  # budget not being consumed
        return self.window_days / self.burn_rate

# Example: availability SLO at 99.9%, current SLI at 99.85%
b = ErrorBudget('availability', 0.999, 30, 0.9985)
print(f'Burn rate: {b.burn_rate:.1f}x')
print(f'Budget remaining: {b.budget_remaining_fraction:.1%}')
print(f'Days until exhausted: {b.days_until_exhausted:.1f}')
# Output:
# Burn rate: 1.5x
# Budget remaining: 85.0%
# Days until exhausted: 20.0
